function loadCss(href) {
    return new Promise((resolve, reject) => {
        if (document.querySelector('link[href="' + href + '"]')) {
            resolve();
            return;
        }
        const link = document.createElement("link");
        link.rel = "stylesheet";
        link.href = href;
        link.onload = resolve;
        link.onerror = reject;
        document.head.appendChild(link);
    });
}

function loadScript(src) {
    return new Promise((resolve, reject) => {
        if (window.agGrid) {
            resolve();
            return;
        }
        const s = document.createElement("script");
        s.src = src;
        s.onload = resolve;
        s.onerror = reject;
        document.head.appendChild(s);
    });
}

var ventasGridApi = null;
var ventasQuickSearch = "";

function mostrarCargaGrid() {
    const el = document.getElementById("ventasLoading");
    if (el) {
        el.style.display = "flex";
    }
}

function ocultarCargaGrid() {
    const el = document.getElementById("ventasLoading");
    if (el) {
        el.style.display = "none";
    }
}

function iniciarGridVentas() {
    const gridDiv = document.querySelector("#myGrid");

    if (!gridDiv || typeof agGrid === "undefined") {
        console.error("No existe #myGrid o no cargó AG Grid");
        return;
    }

    const columnDefs = [
        {
            headerName: "",
            width: 52,
            pinned: "left",
            checkboxSelection: true,
            headerCheckboxSelection: true,
            sortable: false,
            filter: false,
            editable: false,
            suppressMenu: true,
            resizable: false
        },
        {
            field: "idventa",
            headerName: "ID",
            width: 110,
            pinned: "left",
            editable: false,
            filter: "agNumberColumnFilter"
        },
        {
            field: "fecha",
            headerName: "Fecha",
            width: 140,
            editable: false,
            filter: "agTextColumnFilter"
        },
        {
            field: "esnimei",
            headerName: "IMEI",
            minWidth: 220,
            editable: true,
            filter: "agTextColumnFilter"
        },
        {
            field: "simcard",
            headerName: "SIMCARD",
            minWidth: 220,
            editable: true,
            filter: "agTextColumnFilter"
        },
        {
            field: "orden",
            headerName: "Orden",
            minWidth: 180,
            editable: true,
            filter: "agTextColumnFilter"
        },
        {
            field: "contrato",
            headerName: "Contrato",
            minWidth: 160,
            editable: true,
            filter: "agTextColumnFilter"
        },
        {
            field: "cuenta",
            headerName: "Cuenta",
            minWidth: 160,
            editable: true,
            filter: "agTextColumnFilter"
        },
        {
            headerName: "Acciones",
            field: "idventa",
            width: 100,
            pinned: "right",
            sortable: false,
            filter: false,
            editable: false,
            suppressMenu: true,
            cellRenderer: function(params) {
                const id = params.value || "";
                return `
                    <div style="display:flex;align-items:center;justify-content:center;width:100%;">
                        <a href="ventas_edit.php?editid1=${encodeURIComponent(id)}" target="_blank" class="ventas-action-btn" title="Editar">✎</a>
                        <a href="ventas_view.php?editid1=${encodeURIComponent(id)}" target="_blank" class="ventas-action-btn" title="Ver">☰</a>
                    </div>
                `;
            }
        }
    ];

    const datasource = {
        getRows: async function(params) {
            try {
                mostrarCargaGrid();
    
                const payload = {
                    startRow: params.startRow,
                    endRow: params.endRow,
                    sortModel: params.sortModel || [],
                    filterModel: params.filterModel || {},
                    quickSearch: ventasQuickSearch
                };
    
                const resp = await fetch("ventas_aggrid_data.php", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json"
                    },
                    body: JSON.stringify(payload)
                });
    
                const txt = await resp.text();
                let result = {};
    
                try {
                    result = JSON.parse(txt);
                } catch (e) {
                    console.error("JSON inválido en ventas_aggrid_data.php", txt);
                    ocultarCargaGrid();
                    params.failCallback();
                    return;
                }
    
                if (!result.rows || !Array.isArray(result.rows)) {
                    console.error("Formato inesperado:", result);
                    ocultarCargaGrid();
                    params.failCallback();
                    return;
                }
    
                params.successCallback(result.rows, result.lastRow);
                ocultarCargaGrid();
            } catch (e) {
                console.error("Error en getRows:", e);
                ocultarCargaGrid();
                params.failCallback();
            }
        }
    };


    const gridOptions = {
        theme: "legacy",
        columnDefs: columnDefs,
        defaultColDef: {
            sortable: true,
            filter: true,
            floatingFilter: true,
            resizable: true,
            editable: true
        },
        singleClickEdit: true,
        rowSelection: "multiple",
        suppressRowClickSelection: true,
        rowModelType: "infinite",
        cacheBlockSize: 100,
        maxBlocksInCache: 5,
        pagination: true,
        paginationPageSize: 100,
        animateRows: true,
        enableCellTextSelection: true,
        stopEditingWhenCellsLoseFocus: true,
        suppressCellFocus: false,
        suppressMovableColumns: true,
        onCellValueChanged: function(params) {
            if (params.oldValue === params.newValue) return;
            guardarCambioVentas(params);
        }
    };

    ventasGridApi = agGrid.createGrid(gridDiv, gridOptions);
    ventasGridApi.setGridOption("datasource", datasource);

    const txtFiltro = document.getElementById("quickFilterText");
    if (txtFiltro) {
        txtFiltro.addEventListener("keydown", function(e) {
            if (e.key === "Enter") {
                ventasQuickSearch = this.value || "";
                if (ventasGridApi) {
                    mostrarCargaGrid();
                    ventasGridApi.purgeInfiniteCache();
                }
            }
        });
    }

    const btnRecargar = document.getElementById("btnRecargar");
    if (btnRecargar) {
        btnRecargar.addEventListener("click", function() {
            if (ventasGridApi) {
                mostrarCargaGrid();
                ventasGridApi.purgeInfiniteCache();
            }
        });
    }
    
    const btnLimpiarFiltros = document.getElementById("btnLimpiarFiltros");
    if (btnLimpiarFiltros) {
        btnLimpiarFiltros.addEventListener("click", function() {
            ventasQuickSearch = "";
            if (txtFiltro) txtFiltro.value = "";
            if (ventasGridApi) {
                mostrarCargaGrid();
                ventasGridApi.setFilterModel(null);
                ventasGridApi.purgeInfiniteCache();
            }
        });
    }
    
    const btnVerSeleccionados = document.getElementById("btnVerSeleccionados");
    if (btnVerSeleccionados) {
        btnVerSeleccionados.addEventListener("click", function() {
            const rows = ventasGridApi.getSelectedRows();
            const ids = rows.map(r => r.idventa);
            alert(ids.length ? "Seleccionados: " + ids.join(", ") : "No hay filas seleccionadas");
        });
    }
}

function guardarCambioVentas(params) {
    fetch("ventas_aggrid_update.php", {
        method: "POST",
        headers: {
            "Content-Type": "application/json"
        },
        body: JSON.stringify({
            idventa: params.data.idventa,
            campo: params.colDef.field,
            valor: params.newValue
        })
    })
    .then(function(resp) {
        return resp.text();
    })
    .then(function(txt) {
        let r = {};
        try {
            r = JSON.parse(txt);
        } catch (e) {
            console.error("Respuesta inválida de update", e, txt);
            params.node.setDataValue(params.colDef.field, params.oldValue);
            return;
        }

        if (!r.success) {
            params.node.setDataValue(params.colDef.field, params.oldValue);
            alert("No se pudo guardar: " + (r.message || "Error"));
        }
    })
    .catch(function(err) {
        console.error("Error de comunicación", err);
        params.node.setDataValue(params.colDef.field, params.oldValue);
        alert("Error de comunicación con el servidor");
    });
}

setTimeout(async function () {
    try {
        await loadCss("https://cdn.jsdelivr.net/npm/ag-grid-community/styles/ag-grid.css");
        await loadCss("https://cdn.jsdelivr.net/npm/ag-grid-community/styles/ag-theme-quartz.css");
        await loadScript("https://cdn.jsdelivr.net/npm/ag-grid-community/dist/ag-grid-community.min.js");
        iniciarGridVentas();
    } catch (e) {
        console.error("Error cargando AG Grid", e);
        alert("No se pudo cargar AG Grid");
    }
}, 800);

