html, body {
    height: 100%;
}

body {
    background: #f5f6f8;
    font-family: "Segoe UI", Tahoma, Arial, sans-serif;
}

.r-small-page,
.r-content,
.r-form,
.r-body,
.r-page,
.r-container,
.container,
.container-fluid,
[data-location="grid"],
[data-location="above-grid"] {
    max-width: 100% !important;
    width: 100% !important;
}

.ventas-shell {
    width: 100%;
    min-height: calc(100vh - 20px);
    padding: 10px 12px;
    box-sizing: border-box;
}

.ventas-card {
    width: 100%;
    min-height: calc(100vh - 32px);
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 12px;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    box-shadow: 0 1px 2px rgba(16,24,40,.04), 0 8px 20px rgba(16,24,40,.04);
}

.ventas-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
    padding: 14px 16px;
    border-bottom: 1px solid #eceff3;
    background: #ffffff;
}

.ventas-title {
    font-size: 22px;
    font-weight: 700;
    color: #1f2937;
    letter-spacing: .2px;
}

.ventas-subtitle {
    font-size: 12px;
    color: #6b7280;
    margin-top: 2px;
}

.ventas-toolbar {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-wrap: wrap;
}

.ventas-search-wrap {
    position: relative;
}

.ventas-search-icon {
    position: absolute;
    left: 12px;
    top: 50%;
    transform: translateY(-50%);
    color: #8a94a6;
    font-size: 14px;
    pointer-events: none;
}

.ventas-toolbar input {
    width: 300px;
    height: 38px;
    padding: 0 12px 0 34px;
    border: 1px solid #d8dde6;
    border-radius: 8px;
    background: #fff;
    color: #1f2937;
    outline: none;
    transition: .2s ease;
}

.ventas-toolbar input:focus {
    border-color: #9bbcfb;
    box-shadow: 0 0 0 3px rgba(59,130,246,.12);
}

.ventas-toolbar .btn {
    height: 38px;
    border-radius: 8px;
    padding: 0 14px;
    font-weight: 600;
    box-shadow: none;
}

.ventas-toolbar .btn-light {
    background: #f8fafc;
    border: 1px solid #d9dee7;
    color: #374151;
}

.ventas-toolbar .btn-light:hover {
    background: #eef2f7;
}

.ventas-grid-wrap {
    flex: 1;
    min-height: 0;
    padding: 0;
    background: #fff;
}

#myGrid.ventas-grid-theme {
    width: 100%;
    height: 720px;
    min-height: 720px;
    border: 0;
    overflow: hidden;
}

.ventas-grid-theme.ag-theme-quartz {
    --ag-font-family: "Segoe UI", Tahoma, Arial, sans-serif;
    --ag-font-size: 13px;
    --ag-border-color: #e8ebf0;
    --ag-header-background-color: #ffffff;
    --ag-header-foreground-color: #6b7280;
    --ag-header-height: 44px;
    --ag-row-height: 42px;
    --ag-list-item-height: 36px;
    --ag-odd-row-background-color: #fafbfc;
    --ag-row-hover-color: #f3f6fa;
    --ag-selected-row-background-color: #eaf2ff;
    --ag-checkbox-checked-color: #3b82f6;
    --ag-range-selection-border-color: #3b82f6;
    --ag-input-focus-border-color: #9bbcfb;
    --ag-input-focus-box-shadow: 0 0 0 3px rgba(59,130,246,.12);
    --ag-cell-horizontal-border: solid 1px #eceff3;
    --ag-borders: solid 1px;
    --ag-header-column-separator-display: block;
    --ag-header-column-separator-color: #edf1f5;
    --ag-wrapper-border-radius: 0;
}

.ventas-grid-theme .ag-header {
    border-bottom: 1px solid #e9edf3;
}

.ventas-grid-theme .ag-header-cell {
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 1px;
    text-transform: uppercase;
    color: #6b7280;
}

.ventas-grid-theme .ag-cell {
    display: flex;
    align-items: center;
    color: #111827;
    border-right: 1px solid #eceff3;
}

.ventas-grid-theme .ag-cell:last-child {
    border-right: 0;
}

.ventas-action-btn {
    width: 30px;
    height: 30px;
    border: 1px solid #d8dde6;
    background: #fff;
    border-radius: 8px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #6b7280;
    text-decoration: none;
    font-size: 13px;
    margin-right: 6px;
    transition: .18s ease;
}

.ventas-action-btn:hover {
    background: #f4f7fb;
    border-color: #c8d1de;
    color: #374151;
    text-decoration: none;
}

@media (max-width: 900px) {
    .ventas-header {
        flex-direction: column;
        align-items: stretch;
    }

    .ventas-toolbar {
        width: 100%;
    }

    .ventas-search-wrap,
    .ventas-toolbar input {
        width: 100%;
    }
}

.ventas-grid-wrap {
    position: relative;
    flex: 1;
    min-height: 0;
    padding: 0;
    background: #fff;
}

.ventas-loading-overlay {
    position: absolute;
    inset: 0;
    z-index: 20;
    background: rgba(255,255,255,0.72);
    backdrop-filter: blur(1px);
    display: flex;
    align-items: center;
    justify-content: center;
}

.ventas-loading-box {
    min-width: 180px;
    padding: 18px 22px;
    border-radius: 12px;
    background: #ffffff;
    border: 1px solid #dfe5ec;
    box-shadow: 0 10px 30px rgba(16,24,40,.12);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
}

.ventas-spinner {
    width: 34px;
    height: 34px;
    border: 3px solid #dbe6f3;
    border-top: 3px solid #3b82f6;
    border-radius: 50%;
    animation: ventasSpin 0.9s linear infinite;
}

.ventas-loading-text {
    font-size: 13px;
    font-weight: 600;
    color: #334155;
}

@keyframes ventasSpin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}
